var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"저기……. 셰나?","JPN":"あの……シェナ？","ENG":"Um... Shena?","TWN":"那個……世娜？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"혹시 내 말 듣고 있어? 회복하느라 대답 못 하는 거야?","JPN":"聞いてる？　返事しないのは回復に集中してるから？","ENG":"Are you listening? Are you not answering because you're focusing on recovery?","TWN":"你有聽到嗎？你是因為還在恢復中，所以沒辦法回答嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰나, 있잖아…….","JPN":"あのね、シェナ……","ENG":"You know, Shena...","TWN":"世娜，你聽我說……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"다른 단원들이 나더러 셰나의 핵을 흡수하래.","JPN":"団員のみんなが、シェナの核を吸収しろって言うの。","ENG":"The other members told me to absorb your core.","TWN":"其他團員叫我把世娜的核心吸收到……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"조금 모자라지만 나도 그림자니까. 본능적으로 알 수 있어.","JPN":"アタシはバカでもシャドウだから。本能でわかるよ。","ENG":"I'm not that strong, but I'm still a Shadow. I can tell instinctively.","TWN":"雖然我不太聰明，但畢竟也是個暗影，所以我本能地知道，"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지금이라면 네 핵을 차지할 수 있다고.","JPN":"今なら核を奪えるって。","ENG":"I have the power to take your core right now.","TWN":"就現在而言，我是有辦搶走你的核心的。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그치만…. 셰나는 언제나 날 덜떨어졌다고 구박하지만.","JPN":"でもね……シェナはいつもアタシをバカだって怒るけど。","ENG":"And... you always scold me for being stupid, but.","TWN":"可是……雖然你總是說我傻，又愛欺負我。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"여태까지 지휘자님을 제일 많이 도왔는데, 다쳤다고 버려 버리는 건…….","JPN":"今までマエストロのために一番頑張ってきたシェナを、怪我したからといって捨てるのは……","ENG":"You were the most helpful one to the Chief Conductor, and to be thrown away like this just because you're hurt is...","TWN":"但是你一直是對指揮家最盡心盡力的，現在卻因為受傷就要被扔掉……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이 느낌은…… 설마 지휘자님?","JPN":"この気配……もしかしてマエストロ？","ENG":"This feeling... Chief Conductor?","TWN":"這個感覺是……指揮家？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURRPSIE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"수, 숨어야 해! 들켰다간 또 머뭇거리냐고 한소리 듣는다구!","JPN":"か、隠れなきゃ！　バレたらまた愚図って怒られるっ！","ENG":"I-I gotta hide! She's going to scold me if she sees me lounging around!","TWN":"我…我要躲起來！要是被發現我在這，到時候又要唸我心太軟！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"셰나, 제 말이 들리나요?","JPN":"シェナ、私の声が聞こえていますか？","ENG":"Shena, can you hear me?","TWN":"世娜，你有聽到嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……네. 그야 지휘자님의 목소리에는 늘 귀기울이고 있으니까요.","JPN":"……はい。マエストロの声には常に耳を傾けていますから。","ENG":"...Yes. I'm always paying close attention to your voice, Chief Conductor.","TWN":"……有，我一直都有聽到指揮家的聲音。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇군요. 제 곁으로 가까이 와 주세요.","JPN":"そうですか。私の近くに来てください。","ENG":"I see. Come closer to me.","TWN":"是嗎，到我這裡來。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"핵의 상태가 여전하군요. 이래서야 이전처럼 아름다운 음색은 뽐낼 수 없겠어요.","JPN":"核の状態は変わっていませんね。これでは以前のような美しい音色は奏でられないでしょう。","ENG":"Your core is still in bad shape. You will not be able to make the beautiful sounds you used to make before.","TWN":"你的核心依舊沒有起色，這樣就不能演奏出像之前那樣美妙的音色。"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나는 내려오지 않았던가요?","JPN":"ルナは来ていませんか？","ENG":"Did Luna come down here?","TWN":"露娜沒有來過嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};